<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'; import PageHeader from '@/components/PageHeader.vue'; import StatusTag from '@/components/StatusTag.vue'; import type { DashboardStatistics } from '@/types'; import { getDashboardStatistics } from '@/api/dashboard'
const loading=ref(false),stats=ref<DashboardStatistics>({projectCount:0,student_count:0,certificateCount:0,evidencedCount:0,validCount:0,revokedCount:0,recentReceipts:[],recentLogs:[]});const cards=computed(()=>[{label:'实训项目',value:stats.value.projectCount,note:'项目总数',color:'#2563eb'},{label:'学生档案',value:stats.value.student_count,note:'学生总数',color:'#0891b2'},{label:'证书总数',value:stats.value.certificateCount,note:`有效 ${stats.value.validCount} 张`,color:'#7c3aed'},{label:'已存证',value:stats.value.evidencedCount,note:`撤销 ${stats.value.revokedCount} 张`,color:'#059669'}]);async function load(){loading.value=true;try{stats.value=await getDashboardStatistics()}finally{loading.value=false}}onMounted(load)
</script>
<template><div v-loading="loading"><PageHeader title="数据概览" description="实时掌握证书签发、存证与审计情况"><el-button @click="load">刷新</el-button><el-button type="primary" @click="$router.push('/certificates')">签发证书</el-button></PageHeader><div class="metric-grid"><article v-for="card in cards" :key="card.label" class="metric-card"><div class="metric-icon" :style="{background:card.color}"></div><span>{{card.label}}</span><strong>{{card.value}}</strong><small>{{card.note}}</small></article></div><div class="dashboard-grid"><section class="panel"><div class="panel-title"><div><h3>最近存证记录</h3><p>最新回执及确认状态</p></div><el-button text type="primary" @click="$router.push('/chain')">查看全部</el-button></div><el-table :data="stats.recentReceipts" empty-text="暂无存证记录"><el-table-column prop="receipt_id" label="回执编号" min-width="170"/><el-table-column prop="certificate_no" label="证书编号" min-width="180"/><el-table-column prop="evidence_type" label="存证类型"/><el-table-column prop="block_height" label="链高度"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column></el-table></section><section class="panel"><div class="panel-title"><div><h3>最近操作日志</h3><p>关键业务操作</p></div><el-button text type="primary" @click="$router.push('/audit')">查看全部</el-button></div><div class="recent-log" v-for="log in stats.recentLogs" :key="log.id"><div><b>{{log.action}}</b><span>{{log.operator}} · {{log.createdAt}}</span></div><StatusTag :value="log.result"/></div><el-empty v-if="!stats.recentLogs.length" description="暂无操作日志" :image-size="70"/></section></div></div></template>